import React, { useEffect, useState } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  SafeAreaView,
  Alert,
} from 'react-native';
import { useRouter } from 'expo-router';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useAuth } from '@/context/AuthContext';
import { ECR_R_QUESTIONS, LIKERT_LABELS } from '@/utils/questions';
import { calculateECRRScores } from '@/utils/scoring';
import { supabase } from '@/services/supabase';
import { Colors, Spacing, FontSizes, ButtonSizes } from '@/constants/theme';

const ASSESSMENT_PROGRESS_KEY = 'ecr_r_progress';
const TOTAL_QUESTIONS = 36;

export default function AssessmentScreen() {
  const { user } = useAuth();
  const router = useRouter();
  const [currentIndex, setCurrentIndex] = useState(0);
  const [responses, setResponses] = useState<(number | null)[]>(
    new Array(TOTAL_QUESTIONS).fill(null)
  );
  const [submitting, setSubmitting] = useState(false);

  // Load saved progress on mount
  useEffect(() => {
    loadProgress();
  }, []);

  const loadProgress = async () => {
    try {
      const saved = await AsyncStorage.getItem(ASSESSMENT_PROGRESS_KEY);
      if (saved) {
        const data = JSON.parse(saved);
        setResponses(data.responses);
        setCurrentIndex(data.currentIndex);
      }
    } catch {
      // Start fresh
    }
  };

  const saveProgress = async (
    newResponses: (number | null)[],
    newIndex: number
  ) => {
    try {
      await AsyncStorage.setItem(
        ASSESSMENT_PROGRESS_KEY,
        JSON.stringify({ responses: newResponses, currentIndex: newIndex })
      );
    } catch {
      // Silent fail — not critical
    }
  };

  const handleSelect = (value: number) => {
    const newResponses = [...responses];
    newResponses[currentIndex] = value;
    setResponses(newResponses);
    saveProgress(newResponses, currentIndex);
  };

  const handleNext = () => {
    if (currentIndex < TOTAL_QUESTIONS - 1) {
      const nextIndex = currentIndex + 1;
      setCurrentIndex(nextIndex);
      saveProgress(responses, nextIndex);
    }
  };

  const handlePrevious = () => {
    if (currentIndex > 0) {
      const prevIndex = currentIndex - 1;
      setCurrentIndex(prevIndex);
      saveProgress(responses, prevIndex);
    }
  };

  const handleSubmit = async () => {
    // Validate all answered
    const unanswered = responses.findIndex((r) => r === null);
    if (unanswered !== -1) {
      Alert.alert(
        'Incomplete',
        `Please answer all questions. Question ${unanswered + 1} is unanswered.`,
        [
          {
            text: 'Go to question',
            onPress: () => setCurrentIndex(unanswered),
          },
        ]
      );
      return;
    }

    setSubmitting(true);

    try {
      const validResponses = responses as number[];
      const scores = calculateECRRScores(validResponses);

      // Save to Supabase
      const { error } = await supabase.from('ecr_r_assessments').insert({
        user_id: user!.id,
        responses: validResponses,
        anxiety_score: scores.anxietyScore,
        avoidance_score: scores.avoidanceScore,
        attachment_style: scores.attachmentStyle,
        completed_at: new Date().toISOString(),
      });

      if (error) {
        Alert.alert('Error', 'Failed to save results. Please try again.');
        setSubmitting(false);
        return;
      }

      // Clear saved progress
      await AsyncStorage.removeItem(ASSESSMENT_PROGRESS_KEY);

      // Navigate to results
      router.replace({
        pathname: '/(app)/results',
        params: {
          anxietyScore: scores.anxietyScore.toString(),
          avoidanceScore: scores.avoidanceScore.toString(),
          attachmentStyle: scores.attachmentStyle,
        },
      });
    } catch (e) {
      Alert.alert('Error', 'Something went wrong. Please try again.');
      setSubmitting(false);
    }
  };

  const question = ECR_R_QUESTIONS[currentIndex];
  const progress = ((currentIndex + 1) / TOTAL_QUESTIONS) * 100;
  const isLastQuestion = currentIndex === TOTAL_QUESTIONS - 1;
  const currentAnswer = responses[currentIndex];

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.content}>
        {/* Progress */}
        <View style={styles.progressSection}>
          <Text style={styles.progressText}>
            Question {currentIndex + 1} of {TOTAL_QUESTIONS}
          </Text>
          <View style={styles.progressBarBg}>
            <View style={[styles.progressBarFill, { width: `${progress}%` }]} />
          </View>
          <Text style={styles.percentText}>{Math.round(progress)}% complete</Text>
        </View>

        {/* Question */}
        <View style={styles.questionSection}>
          <Text style={styles.questionText}>"{question.text}"</Text>
        </View>

        {/* Likert Scale */}
        <View style={styles.likertSection}>
          {LIKERT_LABELS.map((item) => (
            <TouchableOpacity
              key={item.value}
              style={[
                styles.likertOption,
                currentAnswer === item.value && styles.likertOptionSelected,
              ]}
              onPress={() => handleSelect(item.value)}
            >
              <View
                style={[
                  styles.radio,
                  currentAnswer === item.value && styles.radioSelected,
                ]}
              >
                {currentAnswer === item.value && (
                  <View style={styles.radioInner} />
                )}
              </View>
              <Text
                style={[
                  styles.likertLabel,
                  currentAnswer === item.value && styles.likertLabelSelected,
                ]}
              >
                {item.value} — {item.label}
              </Text>
            </TouchableOpacity>
          ))}
        </View>

        {/* Navigation */}
        <View style={styles.navSection}>
          <TouchableOpacity
            style={[styles.navButton, currentIndex === 0 && styles.navButtonDisabled]}
            onPress={handlePrevious}
            disabled={currentIndex === 0}
          >
            <Text
              style={[
                styles.navButtonText,
                currentIndex === 0 && styles.navButtonTextDisabled,
              ]}
            >
              Previous
            </Text>
          </TouchableOpacity>

          {isLastQuestion ? (
            <TouchableOpacity
              style={[
                styles.submitButton,
                (currentAnswer === null || submitting) && styles.navButtonDisabled,
              ]}
              onPress={handleSubmit}
              disabled={currentAnswer === null || submitting}
            >
              <Text style={styles.submitButtonText}>
                {submitting ? 'Submitting...' : 'See Results'}
              </Text>
            </TouchableOpacity>
          ) : (
            <TouchableOpacity
              style={[
                styles.navButton,
                styles.navButtonPrimary,
                currentAnswer === null && styles.navButtonDisabled,
              ]}
              onPress={handleNext}
              disabled={currentAnswer === null}
            >
              <Text style={styles.navButtonPrimaryText}>Next</Text>
            </TouchableOpacity>
          )}
        </View>
      </View>
    </SafeAreaView>
  );
}

