import React, { useEffect, useState } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  SafeAreaView,
} from 'react-native';
import { useRouter } from 'expo-router';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useAuth } from '@/context/AuthContext';
import { Colors, Spacing, FontSizes, ButtonSizes } from '@/constants/theme';

const ASSESSMENT_PROGRESS_KEY = 'ecr_r_progress';

export default function HomeScreen() {
  const { user, signOut } = useAuth();
  const router = useRouter();
  const [savedProgress, setSavedProgress] = useState<number | null>(null);

  useEffect(() => {
    checkSavedProgress();
  }, []);

  const checkSavedProgress = async () => {
    try {
      const saved = await AsyncStorage.getItem(ASSESSMENT_PROGRESS_KEY);
      if (saved) {
        const data = JSON.parse(saved);
        // Find last answered question
        const answered = data.responses.filter((r: number | null) => r !== null).length;
        if (answered > 0 && answered < 36) {
          setSavedProgress(answered);
        }
      }
    } catch {
      // No saved progress
    }
  };

  const handleStartAssessment = async () => {
    // Clear any saved progress and start fresh
    await AsyncStorage.removeItem(ASSESSMENT_PROGRESS_KEY);
    router.push('/(app)/assessment');
  };

